import React, { useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import { X, Mic, MicOff, Video, VideoOff, Maximize2, Minimize2 } from 'lucide-react';

interface HuddleRoomProps {
  roomName: string;
  onClose: () => void;
}

export default function HuddleRoom({ roomName, onClose }: HuddleRoomProps) {
  const [isExpanded, setIsExpanded] = React.useState(false);

  // Fallback to deterministic Hash URL mapping bridging ephemeral rooms dynamically
  const roomHash = btoa(roomName).replace(/[^a-zA-Z0-9]/g, '').substring(0, 10);
  const wherebyUrl = `https://bridgebox-demo.whereby.com/huddle-${roomHash}?minimal=true`;

  useEffect(() => {
    // Dynamically inject the whereby embed script masking strict dependencies
    const script = document.createElement('script');
    script.src = 'https://cdn.whereby.com/browser-sdk/v2.js';
    script.type = 'module';
    document.head.appendChild(script);

    return () => {
      document.head.removeChild(script);
    };
  }, []);

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95, y: 20 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.95, y: 20 }}
      className={`fixed bottom-6 right-6 z-[60] bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-2xl flex flex-col transition-all duration-300 ${
        isExpanded ? 'w-[800px] h-[600px] max-w-[90vw] max-h-[90vh]' : 'w-[360px] h-[480px]'
      }`}
    >
      <div className="flex items-center justify-between px-4 py-3 bg-slate-800/80 backdrop-blur border-b border-slate-700/50 cursor-move">
        <div className="flex items-center space-x-2">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
          <span className="text-sm font-semibold text-white">Live Huddle</span>
        </div>
        <div className="flex items-center space-x-2 text-slate-400">
          <button
            onClick={() => setIsExpanded(!isExpanded)}
            className="p-1 hover:text-white hover:bg-slate-700 rounded transition-colors"
          >
            {isExpanded ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
          <button
            onClick={onClose}
            className="p-1 text-red-400 hover:text-red-300 hover:bg-slate-700 rounded transition-colors"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      </div>

      <div className="flex-1 bg-black relative">
        {/* @ts-ignore - Whereby Web Component */}
        <whereby-embed
          room={wherebyUrl}
          style={{ width: '100%', height: '100%' }}
          minimal="true"
          audio="on"
          video="on"
        />
      </div>
    </motion.div>
  );
}

// @ts-nocheck
import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Play, Pause, RotateCcw, Activity } from 'lucide-react';
import Card from '../Card';
import Button from '../Button';
import Badge from '../Badge';
import { documentProcessor } from '../../lib/documents/DocumentProcessor';

interface BatchProcessorProps {
  organizationId: string;
}

export default function BatchProcessor({ organizationId }: BatchProcessorProps) {
  const [stats, setStats] = useState({
    pending: 0,
    processing: 0,
    completed: 0,
    failed: 0,
    total: 0,
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadStats();
    const interval = setInterval(loadStats, 5000);
    return () => clearInterval(interval);
  }, [organizationId]);

  const loadStats = async () => {
    try {
      const data = await documentProcessor.getQueueStats(organizationId);
      setStats(data);
    } catch (err) {
      console.error('Failed to load queue stats:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return null;
  }

  if (stats.total === 0) {
    return null;
  }

  const progress = stats.total > 0
    ? ((stats.completed / stats.total) * 100)
    : 0;

  return (
    <motion.div
      initial={{ opacity: 0, y: -10 }}
      animate={{ opacity: 1, y: 0 }}
      className="mb-6"
    >
      <Card className="p-4 bg-slate-900/50 border-slate-800">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="p-2 bg-blue-500/10 rounded-lg">
              <Activity className="w-5 h-5 text-blue-400" />
            </div>
            <div>
              <h3 className="text-sm font-medium text-white mb-1">
                Processing Queue
              </h3>
              <div className="flex items-center gap-3 text-xs text-slate-400">
                <span>
                  <Badge color="amber" className="text-xs mr-1">
                    {stats.pending}
                  </Badge>
                  Pending
                </span>
                <span>
                  <Badge color="blue" className="text-xs mr-1">
                    {stats.processing}
                  </Badge>
                  Processing
                </span>
                <span>
                  <Badge color="green" className="text-xs mr-1">
                    {stats.completed}
                  </Badge>
                  Completed
                </span>
                {stats.failed > 0 && (
                  <span>
                    <Badge color="red" className="text-xs mr-1">
                      {stats.failed}
                    </Badge>
                    Failed
                  </span>
                )}
              </div>
            </div>
          </div>

          <div className="text-right">
            <div className="text-lg font-semibold text-white mb-1">
              {Math.round(progress)}%
            </div>
            <div className="text-xs text-slate-400">
              {stats.completed} of {stats.total}
            </div>
          </div>
        </div>

        <div className="mt-3 h-2 bg-slate-800 rounded-full overflow-hidden">
          <motion.div
            className="h-full bg-blue-500"
            initial={{ width: 0 }}
            animate={{ width: `${progress}%` }}
            transition={{ duration: 0.5 }}
          />
        </div>
      </Card>
    </motion.div>
  );
}

