import { supabase } from '../../supabase';
import type {
  AgentAction,
  ActionExecutionContext,
  ActionExecutionResult,
  ActionHandler,
  ActionType,
} from '../types';

class FlagHighValueLeadHandler implements ActionHandler {
  canHandle(actionType: ActionType): boolean {
    return actionType === 'flag_high_value_lead';
  }

  async validate(action: AgentAction): Promise<{ valid: boolean; error?: string }> {
    const leadId = action.payload.parameters?.lead_id;
    if (!leadId) {
      return { valid: false, error: 'Lead ID is required' };
    }
    return { valid: true };
  }

  async execute(context: ActionExecutionContext): Promise<ActionExecutionResult> {
    const leadId = context.action.payload.parameters?.lead_id;

    if (context.dry_run) {
      return {
        success: true,
        result: { dry_run: true, lead_id: leadId },
        executed_at: new Date().toISOString(),
      };
    }

    try {
      const { error } = await supabase
        .from('bb_leads')
        .update({
          priority: 'high',
          tags: supabase.raw('array_append(tags, ?)', ['high-value']),
        })
        .eq('id', leadId);

      if (error) throw error;

      return {
        success: true,
        result: { lead_id: leadId, flag_added: 'high-value' },
        executed_at: new Date().toISOString(),
      };
    } catch (error: any) {
      return {
        success: false,
        error: error.message,
        executed_at: new Date().toISOString(),
      };
    }
  }
}

class FlagDeliveryRiskHandler implements ActionHandler {
  canHandle(actionType: ActionType): boolean {
    return actionType === 'flag_delivery_risk';
  }

  async validate(action: AgentAction): Promise<{ valid: boolean; error?: string }> {
    const projectId = action.payload.parameters?.project_id;
    if (!projectId) {
      return { valid: false, error: 'Project ID is required' };
    }
    return { valid: true };
  }

  async execute(context: ActionExecutionContext): Promise<ActionExecutionResult> {
    const { project_id, risk_type, severity } = context.action.payload.parameters || {};

    if (context.dry_run) {
      return {
        success: true,
        result: { dry_run: true, project_id },
        executed_at: new Date().toISOString(),
      };
    }

    try {
      const { data: healthRecord, error: healthError } = await supabase
        .from('bb_client_health_scores')
        .select('id')
        .eq('project_id', project_id)
        .single();

      if (healthRecord) {
        await supabase
          .from('bb_client_risks')
          .insert({
            health_score_id: healthRecord.id,
            risk_type: risk_type || 'delivery_delay',
            severity: severity || 'medium',
            description: `Flagged by AI: ${context.action.description}`,
            identified_at: new Date().toISOString(),
            status: 'open',
          });
      }

      return {
        success: true,
        result: { project_id, risk_flagged: true },
        executed_at: new Date().toISOString(),
      };
    } catch (error: any) {
      return {
        success: false,
        error: error.message,
        executed_at: new Date().toISOString(),
      };
    }
  }
}

class EscalateUrgentIssueHandler implements ActionHandler {
  canHandle(actionType: ActionType): boolean {
    return actionType === 'escalate_urgent_issue';
  }

  async validate(action: AgentAction): Promise<{ valid: boolean; error?: string }> {
    const ticketId = action.payload.parameters?.ticket_id;
    if (!ticketId) {
      return { valid: false, error: 'Ticket ID is required' };
    }
    return { valid: true };
  }

  async execute(context: ActionExecutionContext): Promise<ActionExecutionResult> {
    const ticketId = context.action.payload.parameters?.ticket_id;

    if (context.dry_run) {
      return {
        success: true,
        result: { dry_run: true, ticket_id: ticketId },
        executed_at: new Date().toISOString(),
      };
    }

    try {
      const { error } = await supabase
        .from('bb_support_tickets')
        .update({
          priority: 'urgent',
          escalated: true,
          escalated_at: new Date().toISOString(),
        })
        .eq('id', ticketId);

      if (error) throw error;

      return {
        success: true,
        result: { ticket_id: ticketId, escalated: true },
        executed_at: new Date().toISOString(),
      };
    } catch (error: any) {
      return {
        success: false,
        error: error.message,
        executed_at: new Date().toISOString(),
      };
    }
  }
}

export class ActionExecutor {
  private handlers: ActionHandler[] = [
    new FlagHighValueLeadHandler(),
    new FlagDeliveryRiskHandler(),
    new EscalateUrgentIssueHandler(),
  ];

  async executeAction(
    context: ActionExecutionContext
  ): Promise<ActionExecutionResult> {
    const handler = this.handlers.find((h) => h.canHandle(context.action.action_type));

    if (!handler) {
      return {
        success: false,
        error: `No handler found for action type: ${context.action.action_type}`,
        executed_at: new Date().toISOString(),
      };
    }

    const validation = await handler.validate(context.action);
    if (!validation.valid) {
      return {
        success: false,
        error: validation.error || 'Validation failed',
        executed_at: new Date().toISOString(),
      };
    }

    if (context.action.requires_approval && context.action.status !== 'approved') {
      return {
        success: false,
        error: 'Action requires approval before execution',
        executed_at: new Date().toISOString(),
      };
    }

    return handler.execute(context);
  }

  registerHandler(handler: ActionHandler): void {
    this.handlers.push(handler);
  }
}

export const actionExecutor = new ActionExecutor();

// @ts-nocheck
import { supabase } from './supabase';
import { trendDetection } from './trendDetection';
import { predictiveAnalytics } from './predictiveAnalytics';

export type InsightType = 'sales' | 'project' | 'client' | 'automation' | 'strategic';
export type InsightPriority = 'low' | 'medium' | 'high' | 'critical';
export type InsightCategory = 'opportunity' | 'risk' | 'optimization' | 'alert';

export interface AIInsight {
  id: string;
  type: InsightType;
  category: InsightCategory;
  priority: InsightPriority;
  title: string;
  description: string;
  reasoning: string;
  recommendation: string;
  actionItems: string[];
  metadata: Record<string, any>;
  confidence: number;
  impact: 'low' | 'medium' | 'high';
  createdAt: string;
}

export interface SalesRecommendation {
  leadId: string;
  leadName: string;
  score: number;
  reason: string;
  suggestedAction: string;
  urgency: 'low' | 'medium' | 'high';
  estimatedValue: number;
  followUpDate?: string;
}

export interface ProjectRecommendation {
  projectId: string;
  projectName: string;
  issue: string;
  recommendation: string;
  riskLevel: 'low' | 'medium' | 'high';
  suggestedResources?: string[];
  timeline?: string;
}

export interface ClientRecommendation {
  clientId: string;
  clientName: string;
  type: 'upsell' | 'retention' | 'engagement';
  recommendation: string;
  value: number;
  confidence: number;
}

export interface AutomationRecommendation {
  workflow: string;
  frequency: number;
  timeSaved: number;
  complexity: 'low' | 'medium' | 'high';
  roi: number;
  priority: number;
}

export interface StrategicInsight {
  insight: string;
  evidence: string[];
  recommendation: string;
  impact: 'low' | 'medium' | 'high';
  timeframe: string;
}

class AIDecisionEngine {
  private generateId(): string {
    return `insight-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  async analyzeSalesOpportunities(organizationId?: string): Promise<SalesRecommendation[]> {
    let query_leads = supabase.from('bb_leads')
      .select('*')
      .in('status', ['new', 'contacted', 'qualified', 'proposal_sent'])
      .order('created_at', { ascending: false });
    if (organizationId) query_leads = query_leads.eq('organization_id', organizationId);
    const { data: leads } = await query_leads;

    if (!leads) return [];

    const recommendations: SalesRecommendation[] = [];

    for (const lead of leads) {
      let score = 50;
      const reasons: string[] = [];
      let urgency: 'low' | 'medium' | 'high' = 'low';
      let suggestedAction = 'Review and prioritize';

      const daysOld = (Date.now() - new Date(lead.created_at).getTime()) / (1000 * 60 * 60 * 24);
      const lastContactDays = lead.last_contact_date
        ? (Date.now() - new Date(lead.last_contact_date).getTime()) / (1000 * 60 * 60 * 24)
        : daysOld;

      if (lead.estimated_budget > 50000) {
        score += 20;
        reasons.push('High-value opportunity');
      }

      if (lead.status === 'qualified') {
        score += 15;
        reasons.push('Already qualified');
        suggestedAction = 'Send proposal immediately';
        urgency = 'high';
      }

      if (lead.status === 'proposal_sent' && daysOld > 7) {
        score += 25;
        reasons.push('Proposal pending for over a week');
        suggestedAction = 'Follow up on proposal status';
        urgency = 'critical' as any;
      }

      if (lastContactDays > 5 && lead.status !== 'new') {
        score += 10;
        reasons.push('No recent contact');
        suggestedAction = 'Schedule follow-up call';
        urgency = urgency === 'low' ? 'medium' : urgency;
      }

      if (lead.urgency === 'urgent') {
        score += 20;
        reasons.push('Client indicated urgency');
        urgency = 'high';
      }

      if (['healthcare', 'finance', 'logistics'].includes(lead.industry)) {
        score += 5;
        reasons.push('High-converting industry');
      }

      if (daysOld < 2) {
        score += 10;
        reasons.push('Fresh lead');
        suggestedAction = 'Initial contact within 24 hours';
        urgency = urgency === 'low' ? 'medium' : urgency;
      }

      let followUpDate: string | undefined;
      if (urgency === 'high' || urgency === 'critical') {
        followUpDate = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
      } else if (urgency === 'medium') {
        followUpDate = new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString();
      }

      if (score >= 60) {
        recommendations.push({
          leadId: lead.id,
          leadName: lead.company_name || lead.name || 'Unknown',
          score: Math.min(score, 100),
          reason: reasons.join('; '),
          suggestedAction,
          urgency: urgency === 'critical' ? 'high' : urgency,
          estimatedValue: lead.estimated_budget || 0,
          followUpDate,
        });
      }
    }

    return recommendations.sort((a, b) => b.score - a.score).slice(0, 10);
  }

  async analyzeProjectRisks(organizationId?: string): Promise<ProjectRecommendation[]> {
    let query_projects = supabase.from('bb_projects')
      .select('*, project_deliveries(*)')
      .in('status', ['in_progress', 'planning']);
    if (organizationId) query_projects = query_projects.eq('organization_id', organizationId);
    const { data: projects } = await query_projects;

    if (!projects) return [];

    const recommendations: ProjectRecommendation[] = [];

    for (const project of projects) {
      const startDate = new Date(project.start_date);
      const endDate = new Date(project.target_end_date);
      const now = new Date();
      const totalDays = (endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24);
      const elapsedDays = (now.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24);
      const percentComplete = (elapsedDays / totalDays) * 100;

      if (percentComplete > 75 && project.status === 'planning') {
        recommendations.push({
          projectId: project.id,
          projectName: project.name,
          issue: 'Project still in planning phase but nearing deadline',
          recommendation: 'Move to execution immediately or revise timeline',
          riskLevel: 'high',
          timeline: 'Immediate action required',
        });
      }

      const deliveries = project.project_deliveries || [];
      const overdueCount = deliveries.filter((d: any) => {
        return d.status !== 'completed' && new Date(d.due_date) < now;
      }).length;

      if (overdueCount > 0) {
        recommendations.push({
          projectId: project.id,
          projectName: project.name,
          issue: `${overdueCount} deliverable(s) overdue`,
          recommendation: 'Review resource allocation and reassign tasks',
          riskLevel: overdueCount > 2 ? 'high' : 'medium',
          suggestedResources: ['Project manager review', 'Additional developer support'],
        });
      }

      if (project.budget && project.budget < 10000 && totalDays > 90) {
        recommendations.push({
          projectId: project.id,
          projectName: project.name,
          issue: 'Low budget for extended timeline',
          recommendation: 'Reduce scope or negotiate budget increase',
          riskLevel: 'medium',
        });
      }

      if (elapsedDays > 30 && project.status === 'planning') {
        recommendations.push({
          projectId: project.id,
          projectName: project.name,
          issue: 'Extended planning phase',
          recommendation: 'Accelerate planning or break into phases',
          riskLevel: 'medium',
          timeline: 'Within 1 week',
        });
      }
    }

    return recommendations.sort((a, b) => {
      const riskOrder = { high: 3, medium: 2, low: 1 };
      return riskOrder[b.riskLevel] - riskOrder[a.riskLevel];
    });
  }

  async analyzeClientOpportunities(organizationId?: string): Promise<ClientRecommendation[]> {
    let query_organizations = supabase.from('bb_organizations')
      .select('*, bb_projects(*), bb_subscriptions(*)');
    if (organizationId) query_organizations = query_organizations.eq('organization_id', organizationId);
    const { data: organizations } = await query_organizations;

    if (!organizations) return [];

    const recommendations: ClientRecommendation[] = [];

    for (const org of organizations) {
      const projects = org.projects || [];
      const completedProjects = projects.filter((p: any) => p.status === 'completed');
      const activeProjects = projects.filter((p: any) => p.status === 'in_progress');

      if (completedProjects.length > 0 && activeProjects.length === 0) {
        const lastProjectDate = Math.max(
          ...completedProjects.map((p: any) => new Date(p.updated_at).getTime())
        );
        const daysSinceLastProject = (Date.now() - lastProjectDate) / (1000 * 60 * 60 * 24);

        if (daysSinceLastProject > 60 && daysSinceLastProject < 180) {
          recommendations.push({
            clientId: org.id,
            clientName: org.name,
            type: 'engagement',
            recommendation: 'Re-engage client with new service offering',
            value: completedProjects.reduce((sum: number, p: any) => sum + (p.budget || 0), 0) * 0.5,
            confidence: 0.7,
          });
        }
      }

      if (activeProjects.length >= 2) {
        const totalValue = activeProjects.reduce((sum: number, p: any) => sum + (p.budget || 0), 0);
        if (totalValue > 50000) {
          recommendations.push({
            clientId: org.id,
            clientName: org.name,
            type: 'upsell',
            recommendation: 'Client is highly engaged - offer premium support or additional services',
            value: totalValue * 0.3,
            confidence: 0.8,
          });
        }
      }

      const subscription = org.subscriptions?.[0];
      if (subscription && subscription.status === 'active') {
        if (subscription.plan === 'starter' && projects.length > 3) {
          recommendations.push({
            clientId: org.id,
            clientName: org.name,
            type: 'upsell',
            recommendation: 'Client activity suggests need for higher tier plan',
            value: 500 * 12,
            confidence: 0.75,
          });
        }
      }

      if (projects.length === 0 && org.subscription_tier === 'premium') {
        recommendations.push({
          clientId: org.id,
          clientName: org.name,
          type: 'retention',
          recommendation: 'Premium client with no active projects - risk of churn',
          value: 0,
          confidence: 0.6,
        });
      }
    }

    return recommendations.sort((a, b) => (b.confidence * b.value) - (a.confidence * a.value));
  }

  async analyzeAutomationOpportunities(organizationId?: string): Promise<AutomationRecommendation[]> {
    let query_activityLogs = supabase.from('bb_activity_logs')
      .select('action, user_id, created_at')
      .gte('created_at', new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString());
    if (organizationId) query_activityLogs = query_activityLogs.eq('organization_id', organizationId);
    const { data: activityLogs } = await query_activityLogs;

    if (!activityLogs) return [];

    const actionFrequency = new Map<string, number>();
    activityLogs.forEach(log => {
      actionFrequency.set(log.action, (actionFrequency.get(log.action) || 0) + 1);
    });

    const recommendations: AutomationRecommendation[] = [];

    const automationRules = [
      {
        pattern: /lead.*created/i,
        workflow: 'Auto-assign leads to sales team',
        timeSaved: 15,
        complexity: 'low' as const,
      },
      {
        pattern: /proposal.*sent/i,
        workflow: 'Auto-schedule follow-up reminders',
        timeSaved: 30,
        complexity: 'low' as const,
      },
      {
        pattern: /project.*completed/i,
        workflow: 'Auto-trigger satisfaction survey',
        timeSaved: 20,
        complexity: 'medium' as const,
      },
      {
        pattern: /invoice.*overdue/i,
        workflow: 'Auto-send payment reminders',
        timeSaved: 45,
        complexity: 'low' as const,
      },
      {
        pattern: /ticket.*created/i,
        workflow: 'Auto-categorize and route support tickets',
        timeSaved: 10,
        complexity: 'medium' as const,
      },
      {
        pattern: /milestone.*completed/i,
        workflow: 'Auto-notify stakeholders and update status',
        timeSaved: 25,
        complexity: 'low' as const,
      },
    ];

    actionFrequency.forEach((frequency, action) => {
      for (const rule of automationRules) {
        if (rule.pattern.test(action) && frequency > 10) {
          const monthlyTimeSaved = frequency * rule.timeSaved;
          const complexityFactor = rule.complexity === 'low' ? 1 : rule.complexity === 'medium' ? 0.7 : 0.4;
          const roi = (monthlyTimeSaved / 60) * 50 * complexityFactor;

          recommendations.push({
            workflow: rule.workflow,
            frequency,
            timeSaved: monthlyTimeSaved,
            complexity: rule.complexity,
            roi,
            priority: roi > 500 ? 100 : roi > 200 ? 75 : 50,
          });
        }
      }
    });

    return recommendations.sort((a, b) => b.priority - a.priority);
  }

  async generateStrategicInsights(organizationId?: string): Promise<StrategicInsight[]> {
    const [trends, serviceDemand, industryGrowth] = await Promise.all([
      trendDetection.getHotOpportunities(organizationId),
      trendDetection.detectTrendingServices(organizationId, 90),
      trendDetection.detectIndustryGrowth(organizationId, 90),
    ]);

    const insights: StrategicInsight[] = [];

    if (trends.hotServices.length > 0) {
      const topService = trends.hotServices[0];
      if (topService.growthRate > 50) {
        insights.push({
          insight: `${topService.serviceType.replace('_', ' ')} demand surging by ${topService.growthRate.toFixed(0)}%`,
          evidence: [
            `${topService.currentPeriodCount} leads in last 90 days`,
            `$${(topService.totalRevenue / 1000).toFixed(0)}K in potential revenue`,
            `${topService.strength} growth momentum`,
          ],
          recommendation: 'Increase marketing spend and sales focus on this service line',
          impact: 'high',
          timeframe: 'Next 30-60 days',
        });
      }
    }

    if (trends.hotIndustries.length > 0) {
      const topIndustry = trends.hotIndustries[0];
      if (topIndustry.growthRate > 60 && topIndustry.conversionRate > 30) {
        insights.push({
          insight: `${topIndustry.industry} industry shows exceptional growth and conversion`,
          evidence: [
            `${topIndustry.growthRate.toFixed(0)}% growth rate`,
            `${topIndustry.conversionRate.toFixed(0)}% conversion rate`,
            `${topIndustry.currentPeriodCount} active leads`,
          ],
          recommendation: 'Develop industry-specific case studies and specialized service packages',
          impact: 'high',
          timeframe: 'Next 60-90 days',
        });
      }
    }

    const decliningServices = serviceDemand.filter(s => s.direction === 'down' && s.growthRate < -30);
    if (decliningServices.length > 0) {
      const declining = decliningServices[0];
      insights.push({
        insight: `${declining.serviceType.replace('_', ' ')} demand declining significantly`,
        evidence: [
          `${Math.abs(declining.growthRate).toFixed(0)}% decrease`,
          `Only ${declining.currentPeriodCount} leads vs ${declining.previousPeriodCount} prior`,
        ],
        recommendation: 'Re-evaluate pricing, positioning, or consider phasing out',
        impact: 'medium',
        timeframe: 'Next 30 days',
      });
    }

    if (trends.emergingKeywords.length > 3) {
      const keywords = trends.emergingKeywords.slice(0, 3).map((k: any) => k.keyword).join(', ');
      insights.push({
        insight: `Multiple emerging demand signals detected: ${keywords}`,
        evidence: trends.emergingKeywords.slice(0, 3).map((k: any) => `${k.keyword}: ${k.frequency} mentions`),
        recommendation: 'Research market viability and consider service expansion',
        impact: 'medium',
        timeframe: 'Next 90 days',
      });
    }

    const lowConversionIndustries = industryGrowth.filter(
      i => i.currentPeriodCount > 5 && i.conversionRate < 20
    );
    if (lowConversionIndustries.length > 0) {
      const industry = lowConversionIndustries[0];
      insights.push({
        insight: `${industry.industry} has low conversion despite lead volume`,
        evidence: [
          `${industry.currentPeriodCount} leads`,
          `Only ${industry.conversionRate.toFixed(0)}% conversion rate`,
        ],
        recommendation: 'Improve qualification process or adjust targeting for this industry',
        impact: 'medium',
        timeframe: 'Next 30 days',
      });
    }

    return insights;
  }

  async generateInsights(organizationId?: string): Promise<AIInsight[]> {
    const [
      salesRecs,
      projectRecs,
      clientRecs,
      automationRecs,
      strategicInsights,
    ] = await Promise.all([
      this.analyzeSalesOpportunities(organizationId),
      this.analyzeProjectRisks(organizationId),
      this.analyzeClientOpportunities(organizationId),
      this.analyzeAutomationOpportunities(organizationId),
      this.generateStrategicInsights(organizationId),
    ]);

    const insights: AIInsight[] = [];

    salesRecs.slice(0, 3).forEach(rec => {
      insights.push({
        id: this.generateId(),
        type: 'sales',
        category: 'opportunity',
        priority: rec.urgency === 'high' ? 'high' : 'medium',
        title: `Prioritize lead: ${rec.leadName}`,
        description: `Lead scored ${rec.score}/100 and requires attention`,
        reasoning: rec.reason,
        recommendation: rec.suggestedAction,
        actionItems: [
          rec.suggestedAction,
          rec.followUpDate ? `Follow up by ${new Date(rec.followUpDate).toLocaleDateString()}` : 'Schedule follow-up',
        ],
        metadata: {
          leadId: rec.leadId,
          estimatedValue: rec.estimatedValue,
          score: rec.score,
        },
        confidence: rec.score / 100,
        impact: rec.estimatedValue > 50000 ? 'high' : rec.estimatedValue > 20000 ? 'medium' : 'low',
        createdAt: new Date().toISOString(),
      });
    });

    projectRecs.slice(0, 3).forEach(rec => {
      insights.push({
        id: this.generateId(),
        type: 'project',
        category: rec.riskLevel === 'high' ? 'risk' : 'optimization',
        priority: rec.riskLevel === 'high' ? 'high' : 'medium',
        title: `Project attention needed: ${rec.projectName}`,
        description: rec.issue,
        reasoning: `Risk level: ${rec.riskLevel}. ${rec.issue}`,
        recommendation: rec.recommendation,
        actionItems: [
          rec.recommendation,
          ...(rec.suggestedResources || []),
        ],
        metadata: {
          projectId: rec.projectId,
          riskLevel: rec.riskLevel,
        },
        confidence: rec.riskLevel === 'high' ? 0.9 : 0.7,
        impact: rec.riskLevel === 'high' ? 'high' : 'medium',
        createdAt: new Date().toISOString(),
      });
    });

    clientRecs.slice(0, 3).forEach(rec => {
      insights.push({
        id: this.generateId(),
        type: 'client',
        category: rec.type === 'retention' ? 'risk' : 'opportunity',
        priority: rec.type === 'retention' ? 'high' : rec.confidence > 0.7 ? 'high' : 'medium',
        title: `Client ${rec.type}: ${rec.clientName}`,
        description: rec.recommendation,
        reasoning: `Confidence: ${(rec.confidence * 100).toFixed(0)}%. Potential value: $${(rec.value / 1000).toFixed(0)}K`,
        recommendation: rec.recommendation,
        actionItems: [
          rec.type === 'upsell' ? 'Schedule expansion discussion' : 'Review client engagement',
          'Prepare customized proposal',
        ],
        metadata: {
          clientId: rec.clientId,
          type: rec.type,
          value: rec.value,
        },
        confidence: rec.confidence,
        impact: rec.value > 50000 ? 'high' : rec.value > 20000 ? 'medium' : 'low',
        createdAt: new Date().toISOString(),
      });
    });

    automationRecs.slice(0, 2).forEach(rec => {
      insights.push({
        id: this.generateId(),
        type: 'automation',
        category: 'optimization',
        priority: rec.priority > 75 ? 'high' : 'medium',
        title: `Automate: ${rec.workflow}`,
        description: `Save ${rec.timeSaved} minutes/month by automating this workflow`,
        reasoning: `Occurs ${rec.frequency} times/month. ROI: $${rec.roi.toFixed(0)}/month`,
        recommendation: `Implement automation for ${rec.workflow}`,
        actionItems: [
          'Review automation requirements',
          'Configure automation rules',
          'Test and deploy',
        ],
        metadata: {
          workflow: rec.workflow,
          frequency: rec.frequency,
          timeSaved: rec.timeSaved,
          roi: rec.roi,
        },
        confidence: rec.complexity === 'low' ? 0.9 : 0.7,
        impact: rec.roi > 500 ? 'high' : 'medium',
        createdAt: new Date().toISOString(),
      });
    });

    strategicInsights.forEach(insight => {
      insights.push({
        id: this.generateId(),
        type: 'strategic',
        category: insight.impact === 'high' ? 'opportunity' : 'optimization',
        priority: insight.impact === 'high' ? 'high' : 'medium',
        title: insight.insight,
        description: insight.recommendation,
        reasoning: insight.evidence.join(' | '),
        recommendation: insight.recommendation,
        actionItems: [
          insight.recommendation,
          `Timeframe: ${insight.timeframe}`,
        ],
        metadata: {
          evidence: insight.evidence,
          timeframe: insight.timeframe,
        },
        confidence: 0.8,
        impact: insight.impact,
        createdAt: new Date().toISOString(),
      });
    });

    return insights.sort((a, b) => {
      const priorityOrder: Record<InsightPriority, number> = { critical: 4, high: 3, medium: 2, low: 1 };
      return priorityOrder[b.priority] - priorityOrder[a.priority];
    });
  }

  async getRecommendationsForContext(context: {
    type: 'lead' | 'project' | 'client';
    organizationId?: string;
    organizationId?: string;
    id: string;
  }): Promise<AIInsight[]> {
    const allInsights = await this.generateInsights(context.organizationId);

    return allInsights.filter(insight => {
      if (context.type === 'lead' && insight.type === 'sales') {
        return insight.metadata.leadId === context.id;
      }
      if (context.type === 'project' && insight.type === 'project') {
        return insight.metadata.projectId === context.id;
      }
      if (context.type === 'client' && insight.type === 'client') {
        return insight.metadata.clientId === context.id;
      }
      return false;
    });
  }

  async getDashboardInsights(organizationId?: string, limit: number = 5): Promise<AIInsight[]> {
    const insights = await this.generateInsights(organizationId);
    return insights.slice(0, limit);
  }
}

export const aiDecisionEngine = new AIDecisionEngine();

// @ts-nocheck
import { BaseConnector } from '../core/BaseConnector';
import type { ConnectorConfig, SyncResult, ConnectorCapability } from '../types';

interface CSVConfig {
  delimiter: string;
  hasHeader: boolean;
  encoding: string;
}

interface CSVMapping {
  idColumn: string | number;
  dataType: 'event' | 'metric' | 'entity';
  columnMappings: Record<string, string | number>;
  timestampColumn?: string | number;
  timestampFormat?: string;
}

export class CSVConnector extends BaseConnector {
  private config: CSVConfig;
  private mapping: CSVMapping;

  constructor(config: ConnectorConfig) {
    super(config);

    const credentials = this.parseCredentials<CSVConfig>(config.credentials);
    this.config = {
      delimiter: credentials.delimiter || ',',
      hasHeader: credentials.hasHeader !== false,
      encoding: credentials.encoding || 'utf-8'
    };

    const mappingConfig = config.mapping_config as CSVMapping;
    this.mapping = {
      idColumn: mappingConfig?.idColumn || 0,
      dataType: mappingConfig?.dataType || 'entity',
      columnMappings: mappingConfig?.columnMappings || {},
      timestampColumn: mappingConfig?.timestampColumn,
      timestampFormat: mappingConfig?.timestampFormat
    };
  }

  async connect(): Promise<boolean> {
    return true;
  }

  async sync(): Promise<SyncResult> {
    const results: SyncResult = {
      success: false,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: ['CSV connector requires manual import via importCSV method']
    };

    return results;
  }

  async disconnect(): Promise<boolean> {
    return true;
  }

  async test(): Promise<boolean> {
    return true;
  }

  getCapabilities(): ConnectorCapability[] {
    return ['read'];
  }

  async importCSV(file: File): Promise<SyncResult> {
    const startTime = Date.now();
    const results: SyncResult = {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: []
    };

    try {
      const content = await this.readFile(file);
      const rows = await this.parseCSV(content);

      if (rows.length === 0) {
        results.errors.push('No data found in CSV file');
        results.success = false;
        return results;
      }

      let headers: string[] = [];
      let dataRows = rows;

      if (this.config.hasHeader) {
        headers = rows[0];
        dataRows = rows.slice(1);
      } else {
        headers = Array.from({ length: rows[0].length }, (_, i) => `column_${i}`);
      }

      for (const row of dataRows) {
        try {
          const rowData = await this.processRow(row, headers);
          results.recordsProcessed++;
          results.recordsCreated++;
        } catch (error) {
          results.recordsFailed++;
          results.errors.push(`Failed to process row: ${error}`);
        }
      }

      results.duration = Date.now() - startTime;
      return results;
    } catch (error) {
      results.success = false;
      results.errors.push(error instanceof Error ? error.message : 'Unknown error');
      results.duration = Date.now() - startTime;
      return results;
    }
  }

  async importCSVFromText(csvText: string): Promise<SyncResult> {
    const startTime = Date.now();
    const results: SyncResult = {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: []
    };

    try {
      const rows = await this.parseCSV(csvText);

      if (rows.length === 0) {
        results.errors.push('No data found in CSV');
        results.success = false;
        return results;
      }

      let headers: string[] = [];
      let dataRows = rows;

      if (this.config.hasHeader) {
        headers = rows[0];
        dataRows = rows.slice(1);
      } else {
        headers = Array.from({ length: rows[0].length }, (_, i) => `column_${i}`);
      }

      for (const row of dataRows) {
        try {
          await this.processRow(row, headers);
          results.recordsProcessed++;
          results.recordsCreated++;
        } catch (error) {
          results.recordsFailed++;
          results.errors.push(`Failed to process row: ${error}`);
        }
      }

      results.duration = Date.now() - startTime;
      return results;
    } catch (error) {
      results.success = false;
      results.errors.push(error instanceof Error ? error.message : 'Unknown error');
      results.duration = Date.now() - startTime;
      return results;
    }
  }

  private async readFile(file: File): Promise<string> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();

      reader.onload = (e) => {
        const content = e.target?.result;
        if (typeof content === 'string') {
          resolve(content);
        } else {
          reject(new Error('Failed to read file as text'));
        }
      };

      reader.onerror = () => {
        reject(new Error('Failed to read file'));
      };

      reader.readAsText(file, this.config.encoding);
    });
  }

  private async parseCSV(content: string): Promise<string[][]> {
    const rows: string[][] = [];
    const lines = content.split(/\r?\n/);

    for (const line of lines) {
      if (!line.trim()) continue;

      const row = this.parseLine(line);
      rows.push(row);
    }

    return rows;
  }

  private parseLine(line: string): string[] {
    const result: string[] = [];
    let current = '';
    let inQuotes = false;

    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      const nextChar = line[i + 1];

      if (char === '"') {
        if (inQuotes && nextChar === '"') {
          current += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === this.config.delimiter && !inQuotes) {
        result.push(current.trim());
        current = '';
      } else {
        current += char;
      }
    }

    result.push(current.trim());
    return result;
  }

  private async processRow(row: string[], headers: string[]): Promise<void> {
    const sourceId = this.getColumnValue(row, headers, this.mapping.idColumn);

    if (!sourceId) {
      throw new Error('No ID column found in row');
    }

    const normalizedData: Record<string, any> = {};

    for (const [targetField, sourceColumn] of Object.entries(this.mapping.columnMappings)) {
      const value = this.getColumnValue(row, headers, sourceColumn);
      normalizedData[targetField] = this.coerceValue(value);
    }

    let timestamp = new Date();
    if (this.mapping.timestampColumn !== undefined) {
      const timestampValue = this.getColumnValue(row, headers, this.mapping.timestampColumn);
      if (timestampValue) {
        timestamp = this.parseTimestamp(timestampValue);
      }
    }

    const rawData: Record<string, any> = {};
    headers.forEach((header, index) => {
      rawData[header] = row[index];
    });

    await this.storeData({
      connector_id: this.connectorConfig.id,
      source_system: 'csv_import',
      source_id: String(sourceId),
      data_type: this.mapping.dataType,
      raw_data: rawData,
      normalized_data: normalizedData,
      metadata: {
        filename: 'manual_import',
        row_number: row.length
      },
      synced_at: timestamp
    });
  }

  private getColumnValue(row: string[], headers: string[], column: string | number): string {
    if (typeof column === 'number') {
      return row[column] || '';
    }

    const index = headers.indexOf(column);
    if (index === -1) {
      return '';
    }

    return row[index] || '';
  }

  private coerceValue(value: string): any {
    if (!value || value === '') return null;

    if (value.toLowerCase() === 'true') return true;
    if (value.toLowerCase() === 'false') return false;

    const num = Number(value);
    if (!isNaN(num) && value === num.toString()) {
      return num;
    }

    const date = new Date(value);
    if (!isNaN(date.getTime()) && value.match(/^\d{4}-\d{2}-\d{2}/)) {
      return date.toISOString();
    }

    return value;
  }

  private parseTimestamp(value: string): Date {
    if (this.mapping.timestampFormat) {
      return new Date(value);
    }

    const timestamp = Date.parse(value);
    if (!isNaN(timestamp)) {
      return new Date(timestamp);
    }

    return new Date();
  }

  async testConnection(): Promise<boolean> {
    return true;
  }

  async fetchExternalData(options?: Record<string, any>): Promise<any[]> {
    return [];
  }

  async syncNow(): Promise<any> { // @ts-ignore
    return {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      recordsSkipped: 0,
      errors: [],
      duration: 0,
      startedAt: new Date().toISOString(),
      completedAt: new Date().toISOString()
    };
  }

  normalizeData(rawData: any): any[] {
    return rawData;
  }
}

// @ts-nocheck
import { BaseConnector } from '../core/BaseConnector';
import type { ConnectorConfig, SyncResult, ConnectorCapability } from '../types';

interface CustomAPIConfig {
  baseURL: string;
  authType: 'bearer' | 'api_key' | 'basic' | 'none';
  authValue?: string;
  headers?: Record<string, string>;
}

interface EndpointMapping {
  path: string;
  method: 'GET' | 'POST';
  dataPath?: string;
  idField: string;
  dataType: 'event' | 'metric' | 'entity';
  fieldMappings: Record<string, string>;
}

export class CustomAPIConnector extends BaseConnector {
  private config: CustomAPIConfig;
  private mappings: EndpointMapping[];

  constructor(config: ConnectorConfig) {
    super(config);
    this.config = this.parseCredentials<CustomAPIConfig>(config.credentials);
    this.mappings = (config.mapping_config as { endpoints?: EndpointMapping[] })?.endpoints || [];
  }

  async connect(): Promise<boolean> {
    try {
      const headers = this.buildHeaders();
      const response = await fetch(this.config.baseURL, {
        method: 'GET',
        headers
      });

      return response.ok || response.status === 404;
    } catch (error) {
      console.error('Custom API connection failed:', error);
      return false;
    }
  }

  async sync(): Promise<SyncResult> {
    const startTime = new Date();
    const results: SyncResult = {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: []
    };

    try {
      for (const mapping of this.mappings) {
        const endpointResult = await this.syncEndpoint(mapping);
        this.mergeResults(results, endpointResult);
      }

      results.duration = Date.now() - startTime.getTime();
      return results;
    } catch (error) {
      results.success = false;
      results.errors.push(error instanceof Error ? error.message : 'Unknown error');
      results.duration = Date.now() - startTime.getTime();
      return results;
    }
  }

  async disconnect(): Promise<boolean> {
    return true;
  }

  async test(): Promise<boolean> {
    return this.connect();
  }

  getCapabilities(): ConnectorCapability[] {
    return ['read', 'sync'];
  }

  private buildHeaders(): HeadersInit {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      ...this.config.headers
    };

    switch (this.config.authType) {
      case 'bearer':
        if (this.config.authValue) {
          headers['Authorization'] = `Bearer ${this.config.authValue}`;
        }
        break;
      case 'api_key':
        if (this.config.authValue) {
          headers['X-API-Key'] = this.config.authValue;
        }
        break;
      case 'basic':
        if (this.config.authValue) {
          headers['Authorization'] = `Basic ${btoa(this.config.authValue)}`;
        }
        break;
    }

    return headers;
  }

  private async syncEndpoint(mapping: EndpointMapping): Promise<SyncResult> {
    const results: SyncResult = {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: []
    };

    try {
      const url = `${this.config.baseURL}${mapping.path}`;
      const headers = this.buildHeaders();

      const response = await fetch(url, {
        method: mapping.method,
        headers
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch from ${mapping.path}: ${response.statusText}`);
      }

      const data = await response.json();
      let records: any[] = [];

      if (mapping.dataPath) {
        const pathParts = mapping.dataPath.split('.');
        let current = data;
        for (const part of pathParts) {
          current = current[part];
          if (!current) break;
        }
        records = Array.isArray(current) ? current : [current];
      } else {
        records = Array.isArray(data) ? data : [data];
      }

      for (const record of records) {
        try {
          const sourceId = this.extractValue(record, mapping.idField);
          if (!sourceId) {
            results.recordsFailed++;
            results.errors.push(`No ID found for record in ${mapping.path}`);
            continue;
          }

          const normalizedData: Record<string, any> = {};
          for (const [targetField, sourceField] of Object.entries(mapping.fieldMappings)) {
            normalizedData[targetField] = this.extractValue(record, sourceField);
          }

          await this.normalizeAndStore({
            type: mapping.dataType,
            source: `custom_api_${mapping.path}`,
            sourceId: String(sourceId),
            data: normalizedData,
            rawData: record,
            timestamp: new Date()
          });

          results.recordsProcessed++;
          results.recordsCreated++;
        } catch (error) {
          results.recordsFailed++;
          results.errors.push(`Failed to process record from ${mapping.path}: ${error}`);
        }
      }

      return results;
    } catch (error) {
      results.success = false;
      results.errors.push(error instanceof Error ? error.message : 'Unknown error');
      return results;
    }
  }

  private extractValue(obj: any, path: string): any {
    const parts = path.split('.');
    let current = obj;

    for (const part of parts) {
      if (current === null || current === undefined) {
        return undefined;
      }
      current = current[part];
    }

    return current;
  }

  private mergeResults(target: SyncResult, source: SyncResult): void {
    target.recordsProcessed += source.recordsProcessed;
    target.recordsCreated += source.recordsCreated;
    target.recordsUpdated += source.recordsUpdated;
    target.recordsFailed += source.recordsFailed;
    target.errors.push(...source.errors);
    target.success = target.success && source.success;
  }

  private async normalizeAndStore(data: {
    type: 'event' | 'metric' | 'entity';
    source: string;
    sourceId: string;
    data: Record<string, any>;
    rawData: any;
    timestamp: Date;
  }): Promise<void> {
    await this.storeData({
      connector_id: this.connectorConfig.id,
      source_system: data.source,
      source_id: data.sourceId,
      data_type: data.type,
      raw_data: data.rawData,
      normalized_data: data.data,
      metadata: {},
      synced_at: data.timestamp
    });
  }

  async testConnection(): Promise<boolean> {
    return true;
  }

  async fetchExternalData(options?: Record<string, any>): Promise<any[]> {
    return [];
  }

  async syncNow(): Promise<any> { // @ts-ignore
    return {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      recordsSkipped: 0,
      errors: [],
      duration: 0,
      startedAt: new Date().toISOString(),
      completedAt: new Date().toISOString()
    };
  }

  normalizeData(rawData: any): any[] {
    return rawData;
  }
}

// @ts-nocheck
import { BaseConnector } from '../core/BaseConnector';
import type { ConnectorConfig, SyncResult, ConnectorCapability } from '../types';

interface GoogleConfig {
  accessToken: string;
  refreshToken?: string;
  scopes: string[];
}

interface GoogleDriveFile {
  id: string;
  name: string;
  mimeType: string;
  createdTime: string;
  modifiedTime: string;
  size?: string;
  webViewLink?: string;
}

interface GoogleCalendarEvent {
  id: string;
  summary: string;
  description?: string;
  start: { dateTime?: string; date?: string };
  end: { dateTime?: string; date?: string };
  attendees?: Array<{ email: string; responseStatus: string }>;
}

interface GoogleSheetData {
  sheetId: string;
  range: string;
  values: string[][];
}

export class GoogleConnector extends BaseConnector {
  private config: GoogleConfig;

  constructor(config: ConnectorConfig) {
    super(config);
    this.config = this.parseCredentials<GoogleConfig>(config.credentials);
  }

  async connect(): Promise<boolean> {
    try {
      const response = await fetch('https://www.googleapis.com/oauth2/v1/tokeninfo', {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${this.config.accessToken}`
        }
      });

      if (!response.ok) {
        throw new Error('Invalid Google access token');
      }

      const data = await response.json();
      return data.expires_in > 0;
    } catch (error) {
      console.error('Google connection failed:', error);
      return false;
    }
  }

  async sync(): Promise<SyncResult> {
    const startTime = new Date();
    const results: SyncResult = {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: []
    };

    try {
      if (this.config.scopes.includes('https://www.googleapis.com/auth/drive.readonly')) {
        const driveResult = await this.syncGoogleDrive();
        this.mergeResults(results, driveResult);
      }

      if (this.config.scopes.includes('https://www.googleapis.com/auth/calendar.readonly')) {
        const calendarResult = await this.syncGoogleCalendar();
        this.mergeResults(results, calendarResult);
      }

      if (this.config.scopes.includes('https://www.googleapis.com/auth/spreadsheets.readonly')) {
        const sheetsResult = await this.syncGoogleSheets();
        this.mergeResults(results, sheetsResult);
      }

      results.duration = Date.now() - startTime.getTime();
      return results;
    } catch (error) {
      results.success = false;
      results.errors.push(error instanceof Error ? error.message : 'Unknown error');
      results.duration = Date.now() - startTime.getTime();
      return results;
    }
  }

  async disconnect(): Promise<boolean> {
    try {
      await fetch(`https://oauth2.googleapis.com/revoke?token=${this.config.accessToken}`, {
        method: 'POST'
      });
      return true;
    } catch (error) {
      console.error('Google disconnect failed:', error);
      return false;
    }
  }

  async test(): Promise<boolean> {
    return this.connect();
  }

  getCapabilities(): ConnectorCapability[] {
    return ['read', 'sync'];
  }

  private async syncGoogleDrive(): Promise<SyncResult> {
    const results: SyncResult = {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: []
    };

    try {
      const response = await fetch(
        'https://www.googleapis.com/drive/v3/files?pageSize=100&fields=files(id,name,mimeType,createdTime,modifiedTime,size,webViewLink)',
        {
          headers: {
            'Authorization': `Bearer ${this.config.accessToken}`
          }
        }
      );

      if (!response.ok) {
        throw new Error('Failed to fetch Google Drive files');
      }

      const data = await response.json();
      const files: GoogleDriveFile[] = data.files || [];

      for (const file of files) {
        try {
          await this.normalizeAndStore({
            type: 'entity',
            source: 'google_drive',
            sourceId: file.id,
            data: {
              name: file.name,
              type: file.mimeType,
              createdAt: file.createdTime,
              updatedAt: file.modifiedTime,
              size: file.size ? parseInt(file.size) : null,
              url: file.webViewLink
            },
            metadata: {
              mimeType: file.mimeType
            }
          });

          results.recordsProcessed++;
          results.recordsCreated++;
        } catch (error) {
          results.recordsFailed++;
          results.errors.push(`Failed to process file ${file.id}: ${error}`);
        }
      }

      return results;
    } catch (error) {
      results.success = false;
      results.errors.push(error instanceof Error ? error.message : 'Unknown error');
      return results;
    }
  }

  private async syncGoogleCalendar(): Promise<SyncResult> {
    const results: SyncResult = {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: []
    };

    try {
      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

      const response = await fetch(
        `https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin=${thirtyDaysAgo.toISOString()}&maxResults=100&singleEvents=true&orderBy=startTime`,
        {
          headers: {
            'Authorization': `Bearer ${this.config.accessToken}`
          }
        }
      );

      if (!response.ok) {
        throw new Error('Failed to fetch Google Calendar events');
      }

      const data = await response.json();
      const events: GoogleCalendarEvent[] = data.items || [];

      for (const event of events) {
        try {
          const startTime = event.start.dateTime || event.start.date;
          const endTime = event.end.dateTime || event.end.date;

          await this.normalizeAndStore({
            type: 'event',
            source: 'google_calendar',
            sourceId: event.id,
            data: {
              title: event.summary,
              description: event.description,
              startTime,
              endTime,
              attendees: event.attendees?.map(a => ({
                email: a.email,
                status: a.responseStatus
              }))
            },
            timestamp: new Date(startTime)
          });

          results.recordsProcessed++;
          results.recordsCreated++;
        } catch (error) {
          results.recordsFailed++;
          results.errors.push(`Failed to process event ${event.id}: ${error}`);
        }
      }

      return results;
    } catch (error) {
      results.success = false;
      results.errors.push(error instanceof Error ? error.message : 'Unknown error');
      return results;
    }
  }

  private async syncGoogleSheets(): Promise<SyncResult> {
    const results: SyncResult = {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      errors: []
    };

    try {
      const mappingConfig = this.connectorConfig.mapping_config as { spreadsheetId?: string; range?: string } || {};
      const spreadsheetId = mappingConfig.spreadsheetId;

      if (!spreadsheetId) {
        results.errors.push('No spreadsheet ID configured');
        return results;
      }

      const range = mappingConfig.range || 'Sheet1!A1:Z1000';

      const response = await fetch(
        `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${range}`,
        {
          headers: {
            'Authorization': `Bearer ${this.config.accessToken}`
          }
        }
      );

      if (!response.ok) {
        throw new Error('Failed to fetch Google Sheets data');
      }

      const data = await response.json();
      const values: string[][] = data.values || [];

      if (values.length === 0) {
        return results;
      }

      const headers = values[0];
      const rows = values.slice(1);

      for (const row of rows) {
        try {
          const rowData: Record<string, string> = {};
          headers.forEach((header, index) => {
            rowData[header] = row[index] || '';
          });

          await this.normalizeAndStore({
            type: 'metric',
            source: 'google_sheets',
            sourceId: `${spreadsheetId}-${rows.indexOf(row)}`,
            data: rowData,
            timestamp: new Date()
          });

          results.recordsProcessed++;
          results.recordsCreated++;
        } catch (error) {
          results.recordsFailed++;
          results.errors.push(`Failed to process row: ${error}`);
        }
      }

      return results;
    } catch (error) {
      results.success = false;
      results.errors.push(error instanceof Error ? error.message : 'Unknown error');
      return results;
    }
  }

  private mergeResults(target: SyncResult, source: SyncResult): void {
    target.recordsProcessed += source.recordsProcessed;
    target.recordsCreated += source.recordsCreated;
    target.recordsUpdated += source.recordsUpdated;
    target.recordsFailed += source.recordsFailed;
    target.errors.push(...source.errors);
    target.success = target.success && source.success;
  }

  private async normalizeAndStore(data: {
    type: 'event' | 'metric' | 'entity';
    source: string;
    sourceId: string;
    data: Record<string, any>;
    timestamp?: Date;
    metadata?: Record<string, any>;
  }): Promise<void> {
    await this.storeData({
      connector_id: this.connectorConfig.id,
      source_system: data.source,
      source_id: data.sourceId,
      data_type: data.type,
      raw_data: data.data,
      normalized_data: data.data,
      metadata: data.metadata || {},
      synced_at: data.timestamp || new Date()
    });
  }

  async testConnection(): Promise<boolean> {
    return true;
  }

  async fetchExternalData(options?: Record<string, any>): Promise<any[]> {
    return [];
  }

  async syncNow(): Promise<any> { // @ts-ignore
    return {
      success: true,
      recordsProcessed: 0,
      recordsCreated: 0,
      recordsUpdated: 0,
      recordsFailed: 0,
      recordsSkipped: 0,
      errors: [],
      duration: 0,
      startedAt: new Date().toISOString(),
      completedAt: new Date().toISOString()
    };
  }

  normalizeData(rawData: any): any[] {
    return rawData;
  }
}

