interface StripeConfig {
  apiKey: string;
  webhookSecret?: string;
}

interface StripeCustomer {
  id: string;
  email: string;
  name: string;
  created: number;
  metadata: Record<string, string>;
}

interface StripeInvoice {
  id: string;
