      (proposalsResult.data || []).forEach(p => {
        activities.push({
          id: `proposal-${p.id}`,
          type: 'proposal',
          title: 'Proposal Approved',
          description: p.title,
          link: `/app/proposals/${p.id}`,
          timestamp: p.approved_at,
          icon: 'CheckCircle2',
        });
      });

      (projectsResult.data || []).forEach(p => {
        activities.push({
          id: `project-${p.id}`,
          type: 'project',
          title: 'New Project Created',
          description: p.name,
          link: `/app/projects/${p.id}`,
          timestamp: p.created_at,
          icon: 'Package',
        });
      });

      (ticketsResult.data || []).forEach(t => {
        activities.push({
          id: `ticket-${t.id}`,
          type: 'ticket',
          title: 'Support Ticket Opened',
          description: t.title,
          link: `/app/support/${t.id}`,
          timestamp: t.created_at,
          icon: 'MessageSquare',
        });
      });

      (invoicesResult.data || []).forEach(i => {
        activities.push({
          id: `invoice-${i.id}`,
          type: 'invoice',
          title: 'Invoice Paid',
          description: i.invoice_number,
          link: `/app/billing`,
          timestamp: i.paid_at,
          icon: 'DollarSign',
        });
      });

      return activities
        .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
        .slice(0, 15);
    } catch (error) {
      console.error('Failed to fetch recent activity:', error);
      throw error;
    }
  },

  async getExecutiveDashboard(organizationId?: string) {
    const [
      kpis,
