import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Rocket, Filter, TrendingUp, AlertTriangle, Package } from 'lucide-react';
import AppHeader from '../../components/app/AppHeader';
import Card from '../../components/Card';
import KPICard from '../../components/admin/KPICard';
import EmptyState from '../../components/EmptyState';
import LoadingSpinner from '../../components/LoadingSpinner';
import DeliveryPhaseBadge from '../../components/delivery/DeliveryPhaseBadge';
import HealthStatusIndicator from '../../components/delivery/HealthStatusIndicator';
import RiskLevelBadge from '../../components/delivery/RiskLevelBadge';
import { deliveryService, ProjectDeliveryWithDetails, DeliveryPhase, HealthStatus } from '../../lib/db/delivery';

export default function DeliveryOverview() {
  const [deliveries, setDeliveries] = useState<ProjectDeliveryWithDetails[]>([]);
  const [filteredDeliveries, setFilteredDeliveries] = useState<ProjectDeliveryWithDetails[]>([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState<any>(null);
  const [phaseFilter, setPhaseFilter] = useState<string>('all');
  const [healthFilter, setHealthFilter] = useState<string>('all');

  useEffect(() => {
    loadData();
  }, []);

  useEffect(() => {
    filterDeliveries();
  }, [deliveries, phaseFilter, healthFilter]);

  const loadData = async () => {
    try {
      setLoading(true);
      const [deliveriesData, statsData] = await Promise.all([
        deliveryService.getAllActiveDeliveries(),
        deliveryService.getDeliveryStats(),
      ]);
      setDeliveries(deliveriesData);
      setStats(statsData);
    } catch (error) {
      console.error('Failed to load delivery data:', error);
    } finally {
      setLoading(false);
    }
  };

  const filterDeliveries = () => {
    let filtered = [...deliveries];

    if (phaseFilter !== 'all') {
      filtered = filtered.filter((d) => d.delivery_phase === phaseFilter);
    }

    if (healthFilter !== 'all') {
      filtered = filtered.filter((d) => d.health_status === healthFilter);
    }

    setFilteredDeliveries(filtered);
  };

  if (loading) {
    return (
      <>
        <AppHeader title="Delivery OS" subtitle="Manage project execution and delivery" />
        <div className="p-8 flex items-center justify-center">
          <LoadingSpinner size="lg" />
        </div>
      </>
    );
  }

  return (
    <>
      <AppHeader title="Delivery OS" subtitle="Manage project execution and delivery" />

      <div className="p-8 space-y-6">
        {stats && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <KPICard
              title="Active Projects"
              value={stats.total}
              icon={Rocket}
              trend={{ value: 0, isPositive: true }}
            />
            <KPICard
              title="In Build Phase"
              value={stats.by_phase.build}
              icon={Package}
              trend={{ value: 0, isPositive: true }}
            />
            <KPICard
              title="High Risk"
              value={stats.high_risk}
              icon={AlertTriangle}
              trend={{ value: 0, isPositive: false }}
            />
            <KPICard
              title="Healthy Projects"
              value={stats.by_health.green}
              icon={TrendingUp}
              trend={{ value: 0, isPositive: true }}
            />
          </div>
        )}

        <Card glass className="p-6">
          <div className="flex flex-col lg:flex-row gap-4">
            <div className="flex items-center space-x-2">
              <Filter className="w-5 h-5 text-slate-400" />
              <select
                value={phaseFilter}
                onChange={(e) => setPhaseFilter(e.target.value)}
                className="bg-slate-800/50 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
              >
                <option value="all">All Phases</option>
                <option value="discovery">Discovery</option>
                <option value="planning">Planning</option>
                <option value="design">Design</option>
                <option value="build">Build</option>
                <option value="integration">Integration</option>
                <option value="qa">QA</option>
                <option value="deployment">Deployment</option>
                <option value="support">Support</option>
              </select>

              <select
                value={healthFilter}
                onChange={(e) => setHealthFilter(e.target.value)}
                className="bg-slate-800/50 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
              >
                <option value="all">All Health</option>
                <option value="green">Healthy</option>
                <option value="yellow">At Risk</option>
                <option value="red">Critical</option>
              </select>
            </div>
          </div>
        </Card>

        <div className="space-y-4">
          {filteredDeliveries.length === 0 ? (
            <Card glass className="p-12">
              <EmptyState
                icon={Rocket}
                title={phaseFilter !== 'all' || healthFilter !== 'all' ? 'No Projects Found' : 'No Active Deliveries'}
                description={
                  phaseFilter !== 'all' || healthFilter !== 'all'
                    ? 'Try adjusting your filters'
                    : 'Active project deliveries will appear here'
                }
              />
            </Card>
          ) : (
            filteredDeliveries.map((delivery) => (
              <motion.div
                key={delivery.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.3 }}
              >
                <Link to={`/app/delivery/${delivery.project_id}`}>
                  <Card glass className="p-6 hover:border-indigo-500/50 transition-all duration-300 cursor-pointer group">
                    <div className="flex items-start justify-between gap-6">
                      <div className="flex-1">
                        <div className="flex items-start justify-between mb-3">
                          <div>
                            <h3 className="text-xl font-bold text-white group-hover:text-indigo-500 transition-colors mb-2">
                              {delivery.project?.name || 'Unnamed Project'}
                            </h3>
                            {delivery.project?.organizations && (
                              <p className="text-slate-400 text-sm mb-3">
                                {delivery.project.organizations.name}
                              </p>
                            )}
                          </div>
                          <HealthStatusIndicator status={delivery.health_status} size="lg" />
                        </div>

                        <div className="flex flex-wrap items-center gap-2 mb-4">
                          <DeliveryPhaseBadge phase={delivery.delivery_phase} size="sm" />
                          {delivery.risk_level !== 'none' && (
                            <RiskLevelBadge level={delivery.risk_level} size="sm" />
                          )}
                          {delivery.project?.type && (
                            <span className="text-xs px-2 py-1 bg-slate-800/50 text-slate-300 border border-slate-700 rounded-full capitalize">
                              {delivery.project.type.replace(/_/g, ' ')}
                            </span>
                          )}
                        </div>

                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
                          <div>
                            <p className="text-xs text-slate-500 mb-1">Progress</p>
                            <div className="flex items-center space-x-2">
                              <div className="flex-1 h-2 bg-slate-800 rounded-full overflow-hidden">
                                <div
                                  className="h-full bg-indigo-500 transition-all duration-500"
                                  style={{ width: `${delivery.completion_percentage}%` }}
                                />
                              </div>
                              <span className="text-sm font-medium text-white">
                                {delivery.completion_percentage}%
                              </span>
                            </div>
                          </div>

                          {delivery.current_milestone && (
                            <div>
                              <p className="text-xs text-slate-500 mb-1">Current Milestone</p>
                              <p className="text-sm text-white font-medium">{delivery.current_milestone}</p>
                            </div>
                          )}

                          {delivery.team_lead && (
                            <div>
                              <p className="text-xs text-slate-500 mb-1">Team Lead</p>
                              <p className="text-sm text-white font-medium">
                                {delivery.team_lead.full_name || delivery.team_lead.email}
                              </p>
                            </div>
                          )}

                          {delivery.target_completion_date && (
                            <div>
                              <p className="text-xs text-slate-500 mb-1">Target Date</p>
                              <p className="text-sm text-white font-medium">
                                {new Date(delivery.target_completion_date).toLocaleDateString()}
                              </p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  </Card>
                </Link>
              </motion.div>
            ))
          )}
        </div>
      </div>
    </>
  );
}

// @ts-nocheck
import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Zap, Shield, Check, X } from 'lucide-react';
import Card from '../../components/Card';
import Heading from '../../components/Heading';
import LoadingSpinner from '../../components/LoadingSpinner';
import { useAuth } from '../../contexts/AuthContext';
import {
  whiteLabelService,
  FeatureFlag,
  AVAILABLE_FEATURES,
} from '../../lib/db/whiteLabel';
import { hasPermission } from '../../lib/permissions';

export default function FeatureSettings() {
  const { user, currentOrganization, profile } = useAuth();
  const [features, setFeatures] = useState<FeatureFlag[]>([]);
  const [loading, setLoading] = useState(true);
  const [planId] = useState('professional');

  const canEdit = hasPermission(profile?.role, 'settings', 'update');

  useEffect(() => {
    if (currentOrganization) {
      loadFeatures();
    }
  }, [currentOrganization]);

  const loadFeatures = async () => {
    if (!currentOrganization) return;

    try {
      setLoading(true);
      const data = await whiteLabelService.getFeatureFlags(currentOrganization.id);
      setFeatures(data);
    } catch (error) {
      console.error('Failed to load features:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleToggle = async (featureKey: string, enabled: boolean) => {
    if (!currentOrganization || !user || !canEdit) return;

    try {
      await whiteLabelService.toggleFeature(
        currentOrganization.id,
        featureKey,
        enabled,
        user.id
      );
      await loadFeatures();
    } catch (error) {
      console.error('Failed to toggle feature:', error);
      alert('Failed to update feature. Please try again.');
    }
  };

  const getFeatureState = (featureKey: string): boolean => {
    const flag = features.find((f) => f.feature_key === featureKey);
    return flag?.enabled ?? true;
  };

  const featuresByCategory = AVAILABLE_FEATURES.reduce((acc, feature) => {
    if (!acc[feature.category]) {
      acc[feature.category] = [];
    }
    acc[feature.category].push(feature);
    return acc;
  }, {} as Record<string, typeof AVAILABLE_FEATURES>);

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <LoadingSpinner size="lg" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <Heading
          title="Feature Settings"
          subtitle="Enable or disable features for your organization"
          icon={Zap}
        />
        <span className="inline-flex items-center px-2.5 py-1 text-xs font-medium rounded-full bg-blue-500/10 text-blue-400 border border-blue-500/20">{planId} Plan</span>
      </div>

      {!canEdit && (
        <Card className="bg-amber-500/10 border-amber-500/20">
          <p className="text-sm text-amber-300">
            You do not have permission to modify feature settings. Contact your administrator.
          </p>
        </Card>
      )}

      <div className="space-y-6">
        {Object.entries(featuresByCategory).map(([category, categoryFeatures]) => (
          <Card key={category}>
            <div className="flex items-center gap-2 mb-4">
              <h3 className="text-lg font-semibold text-white capitalize">
                {category} Features
              </h3>
              <span className="inline-flex items-center px-2.5 py-1 text-xs font-medium rounded-full bg-slate-500/10 text-slate-400 border border-slate-500/20">
                {categoryFeatures.length}
              </span>
            </div>

            <div className="space-y-3">
              {categoryFeatures.map((feature) => {
                const enabled = getFeatureState(feature.key);
                return (
                  <FeatureRow
                    key={feature.key}
                    feature={feature}
                    enabled={enabled}
                    onToggle={handleToggle}
                    disabled={!canEdit}
                  />
                );
              })}
            </div>
          </Card>
        ))}
      </div>

      {/* Plan Limits Info */}
      <Card className="bg-blue-500/10 border-blue-500/20">
        <div className="flex items-start gap-3">
          <Shield className="w-5 h-5 text-blue-400 mt-0.5" />
          <div>
            <h4 className="text-sm font-medium text-blue-300 mb-1">
              Feature Availability
            </h4>
            <p className="text-sm text-blue-200">
              Features are controlled by your subscription plan. Upgrade to access more features.
            </p>
          </div>
        </div>
      </Card>
    </div>
  );
}

interface FeatureRowProps {
  feature: {
    key: string;
    name: string;
    description: string;
    category: string;
  };
  enabled: boolean;
  onToggle: (key: string, enabled: boolean) => void;
  disabled?: boolean;
}

function FeatureRow({ feature, enabled, onToggle, disabled }: FeatureRowProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className="flex items-center justify-between p-4 bg-slate-800/50 rounded-lg border border-slate-700 hover:border-slate-600 transition-colors"
    >
      <div className="flex-1">
        <div className="flex items-center gap-3 mb-1">
          <h4 className="text-base font-medium text-white">{feature.name}</h4>
          {enabled ? (
            <span className="inline-flex items-center px-2.5 py-1 text-xs font-medium rounded-full bg-green-500/10 text-green-400 border border-green-500/20">
              <Check className="w-3 h-3 mr-1" />
              Enabled
            </span>
          ) : (
            <span className="inline-flex items-center px-2.5 py-1 text-xs font-medium rounded-full bg-slate-500/10 text-slate-400 border border-slate-500/20">
              <X className="w-3 h-3 mr-1" />
              Disabled
            </span>
          )}
        </div>
        <p className="text-sm text-slate-400">{feature.description}</p>
      </div>

      <button
        onClick={() => onToggle(feature.key, !enabled)}
        disabled={disabled}
        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed ${
          enabled ? 'bg-blue-500' : 'bg-slate-700'
        }`}
      >
        <span
          className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
            enabled ? 'translate-x-6' : 'translate-x-1'
          }`}
        />
      </button>
    </motion.div>
  );
}

// @ts-nocheck
import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import {
  Rocket,
  ExternalLink,
  Clock,
  AlertTriangle,
  CheckCircle2,
  Search,
  Plus,
} from 'lucide-react';
import AppHeader from '../../components/app/AppHeader';
import Card from '../../components/Card';
import Button from '../../components/Button';
import LoadingSpinner from '../../components/LoadingSpinner';
import ErrorState from '../../components/ErrorState';
import EmptyState from '../../components/EmptyState';
import DeploymentPhaseBadge from '../../components/implementation/DeploymentPhaseBadge';
import LaunchStatusBadge from '../../components/implementation/LaunchStatusBadge';
import DeploymentReadinessBadge from '../../components/implementation/DeploymentReadinessBadge';
import { implementationService, ImplementationWithProject } from '../../lib/db/implementation';

export default function ImplementationCenter() {
  const [implementations, setImplementations] = useState<ImplementationWithProject[]>([]);
  const [filteredImplementations, setFilteredImplementations] = useState<ImplementationWithProject[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    loadImplementations();
  }, []);

  useEffect(() => {
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      const filtered = implementations.filter(
        (impl) =>
          (impl.project?.name || '').toLowerCase().includes(query) ||
          (impl.project?.organization?.name || '').toLowerCase().includes(query)
      );
      setFilteredImplementations(filtered);
    } else {
      setFilteredImplementations(implementations);
    }
  }, [searchQuery, implementations]);

  const loadImplementations = async () => {
    try {
      setLoading(true);
      setError('');
      const data = await implementationService.getAllImplementations();
      setImplementations(data);
      setFilteredImplementations(data);
    } catch (err: any) {
      setError(err.message || 'Failed to load implementations');
    } finally {
      setLoading(false);
    }
  };

  const getPhaseProgress = (phase: string): number => {
    const phaseOrder = ['setup', 'integration', 'testing', 'staging', 'production', 'post_launch_support'];
    const index = phaseOrder.indexOf(phase);
    return ((index + 1) / phaseOrder.length) * 100;
  };

  const formatLastUpdate = (date?: string): string => {
    if (!date) return 'Never';
    const d = new Date(date);
    const now = new Date();
    const diffMs = now.getTime() - d.getTime();
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

    if (diffDays === 0) return 'Today';
    if (diffDays === 1) return 'Yesterday';
    if (diffDays < 7) return `${diffDays} days ago`;
    return d.toLocaleDateString();
  };

  if (loading) {
    return (
      <>
        <AppHeader title="Implementation Center" subtitle="Track real-world deployments and system rollouts" />
        <div className="flex items-center justify-center h-64">
          <LoadingSpinner size="lg" />
        </div>
      </>
    );
  }

  if (error) {
    return (
      <>
        <AppHeader title="Implementation Center" subtitle="Track real-world deployments and system rollouts" />
        <ErrorState
          message={error}
          onRetry={loadImplementations}
        />
      </>
    );
  }

  return (
    <>
      <AppHeader title="Implementation Center" subtitle="Track real-world deployments and system rollouts" />

      <div className="p-4 md:p-8 space-y-6">
        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search implementations..."
              className="w-full pl-10 pr-4 py-2 bg-slate-800/50 border border-slate-700/50 rounded-lg text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500"
            />
          </div>
        </div>

        {filteredImplementations.length === 0 ? (
          <EmptyState
            icon={Rocket}
            title={searchQuery ? 'No implementations found' : 'No implementations yet'}
            description={
              searchQuery
                ? 'Try adjusting your search criteria'
                : 'Implementations will appear here when projects enter the deployment phase'
            }
          />
        ) : (
          <div className="grid gap-6">
            {filteredImplementations.map((impl) => (
              <motion.div
                key={impl.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
              >
                <Link to={`/app/implementation/${impl.project_id}`}>
                  <Card glass className="p-6 hover:border-slate-600 transition-all group">
                    <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
